// Claude.ai OAuth integration for remote MCP connectors
// This is the mechanism for adding remote MCP servers via Settings > Connectors

// Your server must expose OAuth endpoints Claude.ai can discover:
// GET /.well-known/oauth-authorization-server
{
  "issuer": "https://your-mcp-server.example.com",
  "authorization_endpoint": "https://your-mcp-server.example.com/oauth/authorize",
  "token_endpoint": "https://your-mcp-server.example.com/oauth/token",
  "response_types_supported": ["code"],
  "grant_types_supported": ["authorization_code", "refresh_token"],
  "code_challenge_methods_supported": ["S256"]  // PKCE required
}

// After user clicks "Connect" in Settings > Connectors:
// 1. Claude opens authorization_endpoint in a popup window
// 2. User logs in and authorizes requested scopes
// 3. OAuth callback delivers code to Claude
// 4. Claude exchanges code for access + refresh tokens
// 5. Access token is stored encrypted, per-user, in Claude.ai
// 6. Token is sent as "Authorization: Bearer <token>" on all MCP requests

// The access token is user-scoped:
// - User A and User B each have their own token for your server
// - Your server acts on behalf of the authenticated user only
// - Claude.ai cannot access data beyond what that user can see

